import re
from typing import Any

def scan_pii_in_model(model: Any) -> list[str]:
    pii_patterns = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',  # email
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\b\d{3}[\s-]?\d{3}[\s-]?\d{4}\b',  # phone
    ]

    def extract_fields(obj: Any) -> list[str]:
        if hasattr(obj, '__dict__'):
            return [str(getattr(obj, k)) for k in obj.__dict__]
        elif isinstance(obj, (list, tuple)):
            return [str(item) for item in obj]
        elif isinstance(obj, dict):
            return [str(v) for v in obj.values()]
        return [str(obj)]

    fields = extract_fields(model)
    found_pii = []
    for field in fields:
        for pattern in pii_patterns:
            if re.search(pattern, field):
                found_pii.append(f"PII detected in field: {field[:50]}...")
    return found_pii

