function validateNoPII(extracted: any): string[] {
  const piiRegexes = [
    /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
    /\b\d{3}-\d{2}-\d{4}\b/g,
    /\b\d{3}[\s-]?\d{3}[\s-]?\d{4}\b/g
  ];

  function scanObject(obj: any): string[] {
    const issues: string[] = [];
    const values = Object.values(obj).flatMap(v => 
      Array.isArray(v) ? v : [v]
    );

    values.forEach((value, index) => {
      const strValue = String(value);
      piiRegexes.forEach(regex => {
        if (regex.test(strValue)) {
          issues.push(`PII found in field ${index}: ${strValue.slice(0, 30)}...`);
        }
      });
    });

    return issues;
  }

  return scanObject(extracted);
}

