import { fromOpenai } from 'instructor';
import OpenAI from 'openai';

const client = fromOpenai(new OpenAI());

function scrubPII(content: string): string {
  const piiReplacements: Record<string, string> = {
    /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g: 'REDACTED@example.com',
    /\b\d{3}[\s-]?\d{3}[\s-]?\d{4}\b/g: 'XXX-XXX-XXXX',
    /\b\d{3}-\d{2}-\d{4}\b/g: 'XXX-XX-XXXX'
  };

  let cleaned = content;
  Object.entries(piiReplacements).forEach(([regex, replacement]) => {
    cleaned = cleaned.replace(regex, replacement as string);
  });
  return cleaned;
}

// Intercept and scrub before Instructor validation
const safeClient = {
  ...client,
  chat: {
    ...client.chat,
    completions: {
      ...client.chat.completions,
      create: async (params: any) => {
        const response = await client.chat.completions.create(params);
        if (response.choices[0]?.message?.content) {
          response.choices[0].message.content = scrubPII(
